const expected = (typeof $vars !== 'undefined' && $vars.N8N_API_KEY)
  || (typeof $env !== 'undefined' && $env.N8N_API_KEY)
  || 'PASTE_LARAVEL_N8N_API_KEY_HERE';

if (!expected || expected === 'PASTE_LARAVEL_N8N_API_KEY_HERE') {
  throw new Error('Set N8N_API_KEY in n8n Variables, or edit this node and replace PASTE_LARAVEL_N8N_API_KEY_HERE with the value from Laravel .env.');
}

const headers = $json.headers ?? {};
const provided = headers['x-n8n-api-key'] || headers['X-N8N-API-Key'];

if (provided !== expected) {
  throw new Error('Invalid N8N API key.');
}

const request = $json.body ?? $json;

if (!request.assignment_id) {
  throw new Error('Missing required field: assignment_id');
}

if (!request.google_access_token && !request.access_token) {
  throw new Error('Missing required field: google_access_token');
}

return [{ json: { request, shared_secret: provided } }];

const request = $('Validate Laravel Secret').first().json.request;
const assignment = request.assignment ?? {
  id: request.assignment_id,
  title: request.title ?? 'AutoGrade AI Assignment',
  course_id: request.course_id,
  coursework_id: request.coursework_id,
  grade_mode: request.grade_mode ?? 'draft',
  max_score: request.max_score ?? 100,
  auto_approval: request.auto_approval ?? false,
  auto_email: request.auto_email ?? false,
  min_answer_length: request.min_answer_length ?? 30,
  question_drive_file_id: request.files?.question_drive_file_id ?? '',
  rubric_drive_file_id: request.files?.rubric_drive_file_id ?? '',
  answer_key_drive_file_id: request.files?.answer_key_drive_file_id ?? ''
};

return [{
  json: {
    access_token: request.google_access_token ?? request.access_token,
    token_type: request.google_token_type ?? 'Bearer',
    expires_at: request.google_token_expires_at ?? null,
    assignment,
    request
  }
}];

const tokenResponse = $('Exchange Google Token').first().json;
const request = $('Validate Laravel Secret').first().json.request;
const assignment = tokenResponse.assignment ?? {};
const allSubmissions = $json.studentSubmissions ?? [];

const base = {
  assignment_id: assignment.id ?? request.assignment_id,
  course_id: assignment.course_id ?? request.course_id ?? '',
  coursework_id: assignment.coursework_id ?? request.coursework_id ?? '',
  assignment_title: assignment.title ?? request.title ?? 'AutoGrade AI Assignment',
  max_score: Number(assignment.max_score ?? request.max_score ?? 100),
  auto_approval: Boolean(assignment.auto_approval ?? request.auto_approval ?? false),
  auto_email: Boolean(assignment.auto_email ?? request.auto_email ?? false),
  grade_mode: assignment.grade_mode ?? request.grade_mode ?? 'draft',
  min_answer_length: Number(assignment.min_answer_length ?? request.min_answer_length ?? 30),
  question_drive_file_id: assignment.question_drive_file_id ?? request.files?.question_drive_file_id ?? '',
  rubric_drive_file_id: assignment.rubric_drive_file_id ?? request.files?.rubric_drive_file_id ?? '',
  answer_key_drive_file_id: assignment.answer_key_drive_file_id ?? request.files?.answer_key_drive_file_id ?? ''
};

/* --- DEBUG: Log raw submission data so we can see exactly what Google returned --- */
const debugSubmissions = allSubmissions.map((s) => ({
  id: s.id,
  userId: s.userId,
  state: s.state,
  hasAssignmentSubmission: Boolean(s.assignmentSubmission),
  attachmentCount: (s.assignmentSubmission?.attachments ?? []).length,
  attachmentTypes: (s.assignmentSubmission?.attachments ?? []).map(a => Object.keys(a).join(',')),
  hasShortAnswer: Boolean(s.shortAnswerSubmission),
  hasMultipleChoice: Boolean(s.multipleChoiceSubmission),
  rawKeys: Object.keys(s)
}));

console.log('=== RAW SUBMISSIONS DEBUG ===');
console.log(JSON.stringify(debugSubmissions, null, 2));
console.log('=== Total submissions from API: ' + allSubmissions.length + ' ===');

/* --- Filter: Only grade submissions that have been turned in or returned --- */
const submissions = allSubmissions.filter((s) => {
  const state = String(s.state ?? '').toUpperCase();
  return state === 'TURNED_IN' || state === 'RETURNED' || state === 'RECLAIMED_BY_STUDENT';
});

console.log('=== After state filter: ' + submissions.length + ' (skipped ' + (allSubmissions.length - submissions.length) + ' with state != TURNED_IN/RETURNED) ===');

function answerFromSubmission(submission) {
  return submission?.shortAnswerSubmission?.answer
    ?? submission?.multipleChoiceSubmission?.answer
    ?? '';
}

function attachmentSummary(submission) {
  /* Support both driveFile and link attachments */
  const attachments = submission?.assignmentSubmission?.attachments ?? [];
  return attachments.map((attachment) => {
    const driveFile = attachment.driveFile ?? {};
    const link = attachment.link ?? {};
    const youtubeVideo = attachment.youTubeVideo ?? {};
    const form = attachment.form ?? {};
    return {
      id: driveFile.id ?? '',
      title: driveFile.title ?? link.title ?? youtubeVideo.title ?? form.title ?? '',
      alternateLink: driveFile.alternateLink ?? link.url ?? youtubeVideo.alternateLink ?? form.responseUrl ?? '',
      thumbnailUrl: driveFile.thumbnailUrl ?? link.thumbnailUrl ?? youtubeVideo.thumbnailUrl ?? '',
      type: driveFile.id ? 'driveFile' : (link.url ? 'link' : (youtubeVideo.id ? 'youtubeVideo' : (form.formUrl ? 'form' : 'unknown')))
    };
  });
}

if (!submissions.length) {
  const skippedCount = allSubmissions.length - submissions.length;
  const stateList = allSubmissions.map(s => s.state ?? 'null').join(', ');
  return [{
    json: {
      ...base,
      student_id: 'no-submission',
      student_email: '',
      answer_text: '',
      answer_attachments: [],
      answer_attachment_count: 0,
      submission_state: 'NONE',
      rubric_text: `Rubric Drive file ID: ${base.rubric_drive_file_id}. Add Drive extraction before this node for production PDF/DOCX grading.`,
      answer_key_text: `Answer key Drive file ID: ${base.answer_key_drive_file_id}. Add Drive extraction before this node for production PDF/DOCX grading.`,
      extraction_status: 'FAILED',
      extracted_text_length: 0,
      skipped_not_turned_in: skippedCount,
      _debug_total_submissions: allSubmissions.length,
      _debug_submission_states: stateList,
      _debug_raw: debugSubmissions
    }
  }];
}

return submissions.map((submission) => {
  const answer = String(answerFromSubmission(submission) ?? '');
  const attachments = attachmentSummary(submission);
  const extractedLength = answer.length;
  const extractionStatus = answer.trim()
    ? 'SUCCESS'
    : (attachments.length ? 'PARTIAL' : 'FAILED');

  return {
    json: {
      ...base,
      student_id: String(submission.userId ?? submission.creatorUserId ?? submission.id ?? 'unknown'),
      student_email: '',
      submission_state: String(submission.state ?? 'UNKNOWN').toUpperCase(),
      answer_text: answer || (attachments.length ? `Submission has ${attachments.length} Drive attachment(s), but text extraction is not configured yet.` : ''),
      answer_attachments: attachments,
      answer_attachment_count: attachments.length,
      rubric_text: `Rubric Drive file ID: ${base.rubric_drive_file_id}. Add Drive extraction before this node for full rubric text.`,
      answer_key_text: `Answer key Drive file ID: ${base.answer_key_drive_file_id}. Add Drive extraction before this node for full answer key text.`,
      extraction_status: extractionStatus,
      extracted_text_length: extractedLength,
      _debug_raw_submission: {
        id: submission.id,
        state: submission.state,
        rawKeys: Object.keys(submission),
        assignmentSubmissionKeys: Object.keys(submission.assignmentSubmission ?? {}),
        attachmentCount: (submission.assignmentSubmission?.attachments ?? []).length
      }
    }
  };
});

const items = $input.all();
const gradable = items.filter((item) => {
  const answer = String(item.json.answer_text ?? '').trim();
  const attachments = Array.isArray(item.json.answer_attachments) ? item.json.answer_attachments : [];
  const isPlaceholder = answer.startsWith('Submission has ') || answer.startsWith('TODO:');

  return (answer && !isPlaceholder) || attachments.length > 0;
});

if (gradable.length) {
  return gradable.map((item) => ({
    json: {
      ...item.json,
      skipped_empty_submissions: items.length - gradable.length
    }
  }));
}

const fallback = items[0]?.json ?? {};

return [{
  json: {
    ...fallback,
    student_id: 'no-submitted-work',
    student_email: '',
    answer_text: '',
    answer_attachments: [],
    extraction_status: 'FAILED',
    extracted_text_length: 0,
    skipped_empty_submissions: items.length,
    extraction_notes: ['Tidak ada submission yang memiliki jawaban teks atau attachment. Pastikan siswa menambahkan file di Your work lalu klik Turn in.']
  }
}];

const accessToken = $('Exchange Google Token').first().json.access_token;
const original = $('Build Grading Items').item.json;
const profile = $json ?? {};
const profileName = profile.name ?? {};

let studentEmail = String(profile.emailAddress ?? '').trim();
let studentName = String(profileName.fullName ?? profileName.givenName ?? '').trim();

/* Fallback: if userProfiles didn't return email, try course roster */
if (!studentEmail && original.course_id && original.student_id) {
  try {
    const rosterUrl = `https://classroom.googleapis.com/v1/courses/${encodeURIComponent(original.course_id)}/students`;
    const rosterResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: rosterUrl,
      headers: { Authorization: `Bearer ${accessToken}`, Accept: 'application/json' },
      json: true,
      timeout: 30000
    });
    const students = rosterResponse.students ?? [];
    const match = students.find(s => s.userId === original.student_id);
    if (match) {
      studentEmail = String(match.profile?.emailAddress ?? '').trim();
      if (!studentName) studentName = String(match.profile?.name?.fullName ?? '').trim();
    }
  } catch (err) {
    console.log('Roster fallback failed:', err?.message ?? err);
  }
}

return [{
  json: {
    ...original,
    student_email: studentEmail || original.student_email || '',
    student_name: studentName || original.student_name || ''
  }
}];

const accessToken = $('Exchange Google Token').first().json.access_token;
const output = [];

function toText(value) {
  if (Buffer.isBuffer(value)) {
    return value.toString('utf8');
  }

  if (typeof value === 'string') {
    return value;
  }

  if (value && typeof value === 'object') {
    return JSON.stringify(value, null, 2);
  }

  return '';
}

function canDownloadAsText(name, mimeType) {
  return mimeType.startsWith('text/')
    || ['application/json', 'application/xml', 'application/javascript', 'application/x-php', 'application/octet-stream'].includes(mimeType)
    || /\.(txt|php|md|json|js|html|css|xml)$/i.test(name);
}

async function readAttachment(attachment) {
  const fileId = attachment.id;

  if (!fileId) {
    return { text: '', note: 'Attachment tanpa file ID.' };
  }

  const metadata = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}?fields=id,name,mimeType`,
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: 'application/json'
    },
    json: true,
    timeout: 30000
  });

  const name = String(metadata.name ?? attachment.title ?? fileId);
  const mimeType = String(metadata.mimeType ?? '');
  let url = null;

  if (mimeType === 'application/vnd.google-apps.document') {
    url = `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}/export?mimeType=text/plain`;
  } else if (canDownloadAsText(name, mimeType)) {
    url = `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}?alt=media`;
  } else {
    return {
      text: '',
      note: `${name} (${mimeType || 'unknown MIME'}) belum bisa diekstrak oleh template ini. Gunakan TXT/PHP/Google Docs untuk testing.`
    };
  }

  const content = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: {
      Authorization: `Bearer ${accessToken}`
    },
    json: false,
    encoding: null,
    timeout: 30000
  });

  const text = toText(content).trim();

  if (!text) {
    return { text: '', note: `${name} berhasil diunduh tetapi teksnya kosong.` };
  }

  return {
    text: `--- Attachment: ${name} (${mimeType || 'unknown MIME'}) ---\n${text}`,
    note: ''
  };
}

for (const item of $input.all()) {
  const result = { ...item.json };
  const attachments = Array.isArray(result.answer_attachments) ? result.answer_attachments : [];
  const currentText = String(result.answer_text ?? '').trim();
  const isPlaceholder = currentText.startsWith('Submission has ') || currentText.startsWith('TODO:');
  const texts = [];
  const notes = [];

  if (currentText && !isPlaceholder) {
    texts.push(currentText);
  }

  if (!texts.length && attachments.length) {
    for (const attachment of attachments) {
      try {
        const extracted = await readAttachment.call(this, attachment);

        if (extracted.text) {
          texts.push(extracted.text);
        }

        if (extracted.note) {
          notes.push(extracted.note);
        }
      } catch (error) {
        notes.push(`Gagal membaca attachment ${attachment.title || attachment.id || ''}: ${error?.message ?? error}`);
      }
    }
  }

  result.answer_text = texts.join('\n\n').trim();
  result.extracted_text_length = result.answer_text.length;

  if (result.extracted_text_length > 0) {
    result.extraction_status = 'SUCCESS';
  } else if (attachments.length > 0 || notes.length > 0) {
    result.extraction_status = 'PARTIAL';
  } else {
    result.extraction_status = 'FAILED';
  }

  result.extraction_notes = notes;

  output.push({ json: result });
}

return output;

const accessToken = $('Exchange Google Token').first().json.access_token;
const output = [];

function toText(value) {
  if (Buffer.isBuffer(value)) return value.toString('utf8');
  if (typeof value === 'string') return value;
  if (value && typeof value === 'object') return JSON.stringify(value, null, 2);
  return '';
}

function canDownloadAsText(name, mimeType) {
  return mimeType.startsWith('text/')
    || ['application/json', 'application/xml', 'application/javascript', 'application/x-php', 'application/octet-stream'].includes(mimeType)
    || /\.(txt|php|md|json|js|html|css|xml)$/i.test(name);
}

const GOOGLE_EXPORT = { 'application/vnd.google-apps.document': 'text/plain', 'application/vnd.google-apps.spreadsheet': 'text/csv', 'application/vnd.google-apps.presentation': 'text/plain' };
const BINARY_DOCS = ['application/pdf','application/msword','application/vnd.openxmlformats-officedocument.wordprocessingml.document','application/rtf'];

async function readDriveText(fileId, label) {
  if (!fileId) return { text: '', note: `${label} tidak punya file ID.` };
  let metadata;
  try {
    metadata = await this.helpers.httpRequest({ method: 'GET', url: `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}?fields=id,name,mimeType`, headers: { Authorization: `Bearer ${accessToken}`, Accept: 'application/json' }, json: true, timeout: 30000 });
  } catch (err) { return { text: '', note: `${label} gagal ambil metadata: ${err?.message ?? err}` }; }
  const name = String(metadata.name ?? fileId);
  const mimeType = String(metadata.mimeType ?? '');
  let url = null;

  if (GOOGLE_EXPORT[mimeType]) {
    url = `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}/export?mimeType=${encodeURIComponent(GOOGLE_EXPORT[mimeType])}`;
  } else if (canDownloadAsText(name, mimeType)) {
    url = `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}?alt=media`;
  } else if (BINARY_DOCS.includes(mimeType)) {
    try {
      const copy = await this.helpers.httpRequest({ method: 'POST', url: `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}/copy`, headers: { Authorization: `Bearer ${accessToken}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ name: `_temp_${name}`, mimeType: 'application/vnd.google-apps.document' }), json: true, timeout: 30000 });
      if (!copy.id) return { text: '', note: `${label} ${name}: OCR copy gagal.` };
      const content = await this.helpers.httpRequest({ method: 'GET', url: `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(copy.id)}/export?mimeType=text/plain`, headers: { Authorization: `Bearer ${accessToken}` }, json: false, encoding: null, timeout: 30000 });
      try { await this.helpers.httpRequest({ method: 'DELETE', url: `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(copy.id)}`, headers: { Authorization: `Bearer ${accessToken}` }, timeout: 15000 }); } catch {}
      const text = toText(content).trim();
      return text ? { text: `--- ${label}: ${name} ---\n${text}`, note: '' } : { text: '', note: `${label} ${name}: OCR kosong.` };
    } catch (e) {
      url = `https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}?alt=media`;
    }
  } else {
    return { text: '', note: `${label} ${name} (${mimeType}) tidak didukung. Gunakan TXT, PDF, DOCX, atau Google Docs.` };
  }

  const content = await this.helpers.httpRequest({ method: 'GET', url, headers: { Authorization: `Bearer ${accessToken}` }, json: false, encoding: null, timeout: 30000 });
  const text = toText(content).trim();
  return text ? { text: `--- ${label}: ${name} ---\n${text}`, note: '' } : { text: '', note: `${label} ${name} kosong setelah diunduh.` };
}

for (const item of $input.all()) {
  const result = { ...item.json };
  const notes = Array.isArray(result.extraction_notes) ? [...result.extraction_notes] : [];

  try {
    const rubric = await readDriveText.call(this, result.rubric_drive_file_id, 'Rubrik');
    if (rubric.text) result.rubric_text = rubric.text;
    if (rubric.note) notes.push(rubric.note);
  } catch (error) { notes.push(`Gagal membaca Rubrik: ${error?.message ?? error}`); }

  try {
    const answerKey = await readDriveText.call(this, result.answer_key_drive_file_id, 'Kunci Jawaban');
    if (answerKey.text) result.answer_key_text = answerKey.text;
    if (answerKey.note) notes.push(answerKey.note);
  } catch (error) { notes.push(`Gagal membaca Kunci Jawaban: ${error?.message ?? error}`); }

  try {
    const question = await readDriveText.call(this, result.question_drive_file_id, 'Soal');
    if (question.text) result.question_text = question.text;
    if (question.note) notes.push(question.note);
  } catch (error) { notes.push(`Gagal membaca Soal: ${error?.message ?? error}`); }

  const rubricText = String(result.rubric_text ?? '');
  const answerKeyText = String(result.answer_key_text ?? '');
  const questionText = String(result.question_text ?? '');
  result.rubric_text_available = rubricText.length > 10 && !rubricText.startsWith('Rubric Drive file ID:');
  result.answer_key_text_available = answerKeyText.length > 10 && !answerKeyText.startsWith('Answer key Drive file ID:');
  result.question_text_available = questionText.length > 10;
  result.extraction_notes = notes;

  output.push({ json: result });
}

return output;

