const original = $('Extract Rubric and Answer Key Text').item.json;
let raw = $json.output ?? $json.text ?? $json.response ?? $json;
let parsed = null;
let valid = false;

function tryParse(str) { try { return JSON.parse(str); } catch { return null; } }

function extractJson(input) {
  if (!input) return null;
  if (typeof input === 'object' && !Array.isArray(input)) return input;
  const text = String(input);
  let result = tryParse(text);
  if (result && typeof result === 'object') return result;
  const fenceMatch = text.match(/```(?:json)?\s*\n?([\s\S]*?)\n?\s*```/i);
  if (fenceMatch) { result = tryParse(fenceMatch[1].trim()); if (result && typeof result === 'object') return result; }
  const fb = text.indexOf('{'); const lb = text.lastIndexOf('}');
  if (fb !== -1 && lb > fb) { result = tryParse(text.substring(fb, lb + 1)); if (result && typeof result === 'object') return result; }
  const lines = text.split('\n'); let js = -1;
  for (let i = 0; i < lines.length; i++) { if (lines[i].trim().startsWith('{')) { js = i; break; } }
  if (js >= 0) { const c = lines.slice(js).join('\n').trim(); const l = c.lastIndexOf('}'); if (l > 0) { result = tryParse(c.substring(0, l + 1)); if (result && typeof result === 'object') return result; } }
  return null;
}

parsed = extractJson(raw);
if (parsed && typeof parsed.output === 'object' && !Array.isArray(parsed.output)) parsed = parsed.output;
if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) { valid = true; } else { valid = false; parsed = {}; }

/* Score scaling */
const assignmentMaxScore = Number(original.max_score ?? 100);
const aiMaxScore = Number(parsed.max_score ?? parsed.total_score !== undefined ? (Number(parsed.max_total_score ?? parsed.max_score ?? assignmentMaxScore)) : assignmentMaxScore);
const aiRawScore = Number(parsed.score ?? parsed.total_score ?? parsed.score_ai ?? 0);
let score = 0;
if (Number.isFinite(aiRawScore) && aiMaxScore > 0) {
  score = (aiMaxScore !== assignmentMaxScore) ? Math.round((aiRawScore / aiMaxScore) * assignmentMaxScore * 100) / 100 : aiRawScore;
  score = Math.min(Math.max(score, 0), assignmentMaxScore);
}
let rubricBreakdown = Array.isArray(parsed.rubric_breakdown) ? parsed.rubric_breakdown : [];
if (aiMaxScore !== assignmentMaxScore && rubricBreakdown.length > 0) {
  const sf = assignmentMaxScore / aiMaxScore;
  rubricBreakdown = rubricBreakdown.map(item => ({ ...item, score: Math.round(Number(item.score ?? 0) * sf * 100) / 100, max_score: Math.round(Number(item.max_score ?? 0) * sf * 100) / 100 }));
}

const confidence = String(parsed.confidence ?? 'LOW').toUpperCase();
const extractionStatus = String(parsed.extraction_status ?? original.extraction_status ?? 'PARTIAL').toUpperCase();
const extractedLength = Number(parsed.extracted_text_length ?? original.extracted_text_length ?? 0);
const notes = Array.isArray(original.extraction_notes) ? original.extraction_notes.filter(Boolean) : [];
const reasonParts = [String(parsed.reason ?? (valid ? '' : 'Output AI Agent tidak valid JSON.'))];
if (aiMaxScore !== assignmentMaxScore && valid) reasonParts.push(`Skor di-scale dari ${aiRawScore}/${aiMaxScore} ke ${score}/${assignmentMaxScore}.`);
if (notes.length && extractionStatus !== 'SUCCESS') reasonParts.push(`Catatan ekstraksi: ${notes.join(' | ')}`);

return [{ json: {
  assignment_id: original.assignment_id,
  assignment_title: String(original.assignment_title ?? 'AutoGrade AI Assignment'),
  student_id: String(parsed.student_id ?? original.student_id ?? 'unknown'),
  student_name: String(original.student_name ?? ''),
  student_email: String(parsed.student_email ?? original.student_email ?? ''),
  score,
  confidence: ['LOW','MEDIUM','HIGH'].includes(confidence) ? confidence : 'LOW',
  needs_review: Boolean(parsed.needs_review ?? confidence !== 'HIGH'),
  extraction_status: ['SUCCESS','PARTIAL','FAILED'].includes(extractionStatus) ? extractionStatus : 'PARTIAL',
  extracted_text_length: Number.isFinite(extractedLength) ? extractedLength : 0,
  output_json_valid: valid && Boolean(parsed.output_json_valid ?? true),
  reason: reasonParts.filter(Boolean).join(' '),
  feedback_email: String(parsed.feedback_email ?? ''),
  rubric_breakdown: rubricBreakdown,
  email_sent: false,
  max_score: assignmentMaxScore,
  auto_approval: Boolean(original.auto_approval),
  auto_email: Boolean(original.auto_email),
  min_answer_length: Number(original.min_answer_length ?? 30),
  extraction_notes: notes,
  answer_attachment_count: Number(original.answer_attachment_count ?? 0),
  skipped_empty_submissions: Number(original.skipped_empty_submissions ?? 0),
  workflow_version: 'v3-soal-rubric-scaling',
  rubric_text_available: Boolean(original.rubric_text_available),
  answer_key_text_available: Boolean(original.answer_key_text_available),
  question_text_available: Boolean(original.question_text_available)
}}];

const accessToken = $('Exchange Google Token').first().json.access_token;
const output = [];

function base64Url(value) {
  return Buffer.from(value, 'utf8')
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

function encodedSubject(value) {
  return `=?UTF-8?B?${Buffer.from(value, 'utf8').toString('base64')}?=`;
}

function mimeMessage(result) {
  const studentName = String(result.student_name || '').trim();
  const greeting = studentName ? `Halo ${studentName},` : 'Halo,';
  const subject = `Hasil Penilaian: ${result.assignment_title || 'Tugas'}`;
  const scoreLine = `Skor: ${result.score}/${result.max_score}`;
  const body = [
    greeting,
    '',
    `Berikut hasil penilaian untuk ${result.assignment_title || 'tugas Anda'}.`,
    scoreLine,
    '',
    result.feedback_email || result.reason || 'Feedback belum tersedia.',
    '',
    'Terima kasih.'
  ].join('\n');

  return [
    `To: ${result.student_email}`,
    `Subject: ${encodedSubject(subject)}`,
    'MIME-Version: 1.0',
    'Content-Type: text/plain; charset=UTF-8',
    'Content-Transfer-Encoding: 8bit',
    '',
    body
  ].join('\r\n');
}

for (const item of $input.all()) {
  const result = { ...item.json };
  result.email_sent = false;

  if (!result.email_should_send) {
    output.push({ json: result });
    continue;
  }

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://gmail.googleapis.com/gmail/v1/users/me/messages/send',
      headers: {
        Authorization: `Bearer ${accessToken}`,
        'Content-Type': 'application/json'
      },
      body: {
        raw: base64Url(mimeMessage(result))
      },
      json: true,
      timeout: 30000
    });

    result.email_sent = Boolean(response?.id);
    result.gmail_message_id = response?.id ?? null;

    if (!result.email_sent) {
      result.reason = [result.reason, 'Gmail API tidak mengembalikan message id.'].filter(Boolean).join(' ');
    }
  } catch (error) {
    result.email_sent = false;
    result.email_error = String(error?.message ?? error);
    result.reason = [result.reason, `Email gagal dikirim: ${result.email_error}`].filter(Boolean).join(' ');
  }

  output.push({ json: result });
}

return output;
